```javascript
function solve(s) {
    const existing = new Set();
    const segments = [];
    let i = 0;
    while (i < s.length) {
        let current = '';
        while (true) {
            current += s[i];
            if (!existing.has(current)) {
                existing.add(current);
                segments.push(current);
                break;
            } else {
                i += 1;
            }
        }
        i += 1;
    }
    return segments;
}
```

